            elif predicate == "leaderParty":
                details.append(f"has a leader party of {obj}")
            elif predicate == "runwaySurfaceType":
                details.append(f"has a runway surface type of {obj}")
            elif predicate == "demonym":
                details.append(f"whose people are called {obj}")
            elif predicate == "division":
                details.append(f"belongs to the division of {obj}")
            elif predicate == "class":
                details.append(f"belongs to the class of {obj}")
            elif predicate == "order":
                details.append(f"belongs to the order of {obj}")
            elif predicate == "1stRunwayLengthMetre":
                details.append(f"has a first runway length of {obj} metres")
            else:
                details.append(f"has a {predicate} of {obj}")

